11526           if (match(V, m_Select(m_Value(), m_Value(), m_Value()))) {
11527             if (!SelectOp)
11528               SelectOp = cast<Instruction>(V);
11529             return true;
11530           }
11531           auto *ZExt = dyn_cast<ZExtInst>(V);
11532           return (ZExt && ZExt->getSrcTy()->isIntegerTy(1)) ||
11533                  isa<PoisonValue>(V);
11534         })) {
